@page "/privacy"
@attribute [ExcludeFromInteractiveRouting]
@attribute [Microsoft.AspNetCore.Components.Web.StreamRendering]
@using Microsoft.AspNetCore.Http

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

@if (HasConsented)
{
    <div class="alert alert-success" role="alert">
        ✓ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning" role="alert">
        You have not yet accepted our cookie policy.
    </div>
}

<h2>Cookie Usage</h2>
<p>
    This site uses cookies to improve your experience. By continuing to use this site,
    you agree to our use of cookies.
</p>

<h2>Data Collection</h2>
<p>
    We collect only the information necessary to provide and improve our services.
    Your data is never sold to third parties.
</p>

<h2>Your Rights</h2>
<p>
    You have the right to access, correct, or delete your personal data at any time.
    Contact us if you wish to exercise these rights.
</p>

@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private bool HasConsented { get; set; }

    protected override void OnInitialized()
    {
        HasConsented = HttpContext?.Request.Cookies.ContainsKey("consent") == true;
    }
}

